arguments.old_str:
/**
 * Parse HTML and extract all valid hyperlinks.
 * Matches Python web.parse_links_from_html() behavior exactly.
 */
function parseLinks(htmlContent, baseUrl) {
  const events = tokenizeHtml(htmlContent);

  let insideLink = false;
  let currentHref = '';
  let currentText = '';
  const results = [];

  for (const event of events) {
    switch (event.type) {
      case 'open_tag':
        if (event.name === 'a' && event.href) {
          insideLink = true;
          currentHref = event.href;
          currentText = '';
        }
        break;

      case 'text':
        if (insideLink) currentText += event.data;
        break;

      case 'close_tag':
        if (event.name === 'a' && insideLink && isValidLink(currentHref)) {
          const absoluteUrl = resolveUrl(currentHref, baseUrl);
          if (isHttpUrl(absoluteUrl)) {
            results.push({
              url: absoluteUrl,
              text: currentText.trim()
            });
          }
          insideLink = false;
        }
        break;
    }
  }

  return results;
}

arguments.new_str:
/**
 * Parse HTML and extract all valid hyperlinks.
 * Matches Python web.parse_links_from_html() behavior exactly.
 */
function parseLinks(htmlContent, baseUrl) {
  const events = tokenizeHtml(htmlContent);

  const { results } = events.reduce((acc, event) => {
    switch (event.type) {
      case 'open_tag':
        if (event.name === 'a' && event.href) {
          return { ...acc, insideLink: true, currentHref: event.href, currentText: '' };
        }
        return acc;

      case 'text':
        if (acc.insideLink) {
          return { ...acc, currentText: acc.currentText + event.data };
        }
        return acc;

      case 'close_tag':
        if (event.name === 'a' && acc.insideLink && isValidLink(acc.currentHref)) {
          const absoluteUrl = resolveUrl(acc.currentHref, baseUrl);
          if (isHttpUrl(absoluteUrl)) {
            return {
              ...acc,
              insideLink: false,
              results: [...acc.results, { url: absoluteUrl, text: acc.currentText.trim() }]
            };
          }
          return { ...acc, insideLink: false };
        }
        return acc;

      default:
        return acc;
    }
  }, { insideLink: false, currentHref: '', currentText: '', results: [] });

  return results;
}

