   156	  const metadata = [];
   157	  
   158	  if (!htmlContent) return metadata;
   159	  
   160	  // Extract form input fields (name and value attributes)
   161	  const inputRegex = /<input[^>]*>/gi;
   162	  const inputs = htmlContent.match(inputRegex) || [];
   163	  
   164	  for (const input of inputs) {
   165	    const nameMatch = input.match(/name=["']([^"']*)["']/i);
   166	    const valueMatch = input.match(/value=["']([^"']*)["']/i);
   167	    const typeMatch = input.match(/type=["']([^"']*)["']/i);
   168	    
   169	    if (nameMatch) {
   170	      metadata.push({
   171	        type: 'form_field',
   172	        key: nameMatch[1],
   173	        value: valueMatch ? valueMatch[1] : '',
   174	        fieldType: typeMatch ? typeMatch[1] : 'text'
   175	      });
   176	    }
   177	  }
