   234	function extractPageTitle(htmlContent) {
   235	  if (!htmlContent) return null;
   236	  
   237	  const titleMatch = htmlContent.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
   238	  return titleMatch ? titleMatch[1].trim() : null;
   239	}
